parameters.jsCode:
const expression = $fromAI('expression', 'the mathematical expression to evaluate');
try {
  const clean = expression.replace(/Math\./g, '');
  if (/[a-zA-Z_$]/.test(clean)) {
    return [{ json: { result: 'Error: only numeric expressions and Math functions allowed' } }];
  }
  const result = Function('"use strict"; const Math = globalThis.Math; return (' + expression + ')')();
  return [{ json: { result: String(result) } }];
} catch(e) {
  return [{ json: { result: 'Error: ' + e.message } }];
}

